#nullable disable

using System;
using System.Threading;
using System.Threading.Tasks;
using Altinn.Platform.Storage.Interface.Models;

namespace Altinn.Platform.Storage.Services;

/// <summary>
/// Service responsible for removing data elements that were generated by a
/// specific process task, typically invoked when that task is (re-)entered.
/// </summary>
public interface IProcessDataCleanupService
{
    /// <summary>
    /// Finds all data elements on <paramref name="instance"/> whose
    /// <see cref="DataElement.References"/> contain a reference matching
    /// <c>{Relation = GeneratedFrom, ValueType = Task, Value = taskId}</c>.
    /// </summary>
    /// <param name="instance">The instance whose data elements should be evaluated.</param>
    /// <param name="taskId">The id of the task that the instance is entering.</param>
    /// <param name="cancellationToken">A cancellation token.</param>
    /// <returns>The matching data elements.</returns>
    Task<IReadOnlyList<DataElement>> GetGeneratedFromTaskDataElements(
        Instance instance,
        string taskId,
        CancellationToken cancellationToken
    );
}
